#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld", &N);
        if(N==2 || N==4 || N>=6) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

